const input = $input.first().json;
const body = input.body || input;  // Handle both wrapped and direct input

const project = (body.project || '').trim().toLowerCase().replace(/\s+/g, '-');
const action = body.action || 'review';
const reviewNum = body.reviewNum || 1;

if (!project) throw new Error('project required');
if (!['review', 'decide', 'gate'].includes(action)) throw new Error('invalid action');

const wp = `/home/node/workspace/${project}`;
const councilHandoff = reviewNum === 1 ?
  `${wp}/handoffs/004-council-review.md` :
  `${wp}/handoffs/004-council-review-r${reviewNum}.md`;

return [{
  json: {
    project,
    action,
    decision: body.decision || '',
    gateDecision: body.gate_decision || '',
    revisions: body.revisions || '',
    reviewNum,
    wp,
    prdHandoff: `${wp}/handoffs/003-prd-refined.md`,
    councilHandoff,
    prdDir: `${wp}/tasks`,
    promptsDir: '/home/node/prompts',
    skillsDir: '/home/node/skills'
  }
}];

const fs = require('fs');
const d = $input.first().json;
let prd;
try {
  prd = fs.readFileSync(d.prdHandoff, 'utf8');
} catch(e) {
  throw new Error(`PRD not found at ${d.prdHandoff}. Run Phase 3 first.`);
}
return [{ json: { ...d, prd } }];

const d = $input.first().json;
const prd = d.prd;
const e = [];
const fm = prd.match(/^---\n([\s\S]*?)\n---/);
if (!fm) e.push('Missing frontmatter');
else {
  const f = fm[1];
  if (!/phase:\s*prd-synthesis/.test(f)) e.push('phase must be prd-synthesis');
  if (!/version:\s*v\d+/.test(f)) e.push('version missing');
}
const secs = [
  [/#{1,3}\s+(?:\d+\.\s+)?Executive Summary/i, 'Executive Summary'],
  [/#{1,3}\s+(?:\d+\.\s+)?Functional Requirements/i, 'Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?Non-Functional Requirements/i, 'Non-Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?User Stories/i, 'User Stories'],
  [/#{1,3}\s+(?:\d+\.\s+)?Architecture/i, 'Architecture'],
  [/#{1,3}\s+(?:\d+\.\s+)?Risk/i, 'Risk Assessment'],
  [/#{1,3}\s+(?:\d+\.\s+)?MVP/i, 'MVP']
];
for (const [p, n] of secs) if (!p.test(prd)) e.push(`Missing ${n}`);
const frCt = (prd.match(/\*\*FR-\d+:/g) || []).length;
if (frCt < 3) e.push(`< 3 FRs (${frCt})`);
const nfr = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Non-Functional[\s\S]*?(?=\n#{1,3}\s)/i)?.[0] || '';
if (nfr && !/\d+\s*(?:ms|s|%|concurrent|users|GB|MB)/.test(nfr)) e.push('NFR lacks numeric targets');
const usCt = (prd.match(/\*\*US-\d+:/g) || []).length;
if (usCt < 3) e.push(`< 3 user stories (${usCt})`);
const risk = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Risk[\s\S]*?(?=\n#{1,3}\s|$)/i)?.[0] || '';
const riskRows = (risk.match(/\|[^|\n]+\|[^|\n]+\|[^|\n]+\|[^|\n]+\|/g) || []).filter(r => !r.includes('---') && !/likelihood/i.test(r));
if (riskRows.length < 2) e.push(`< 2 risks (${riskRows.length})`);
if (e.length > 0) return [{ json: { ...d, valid: false, errors: e } }];
return [{ json: { ...d, valid: true } }];

const fs = require('fs');
const d = $input.first().json;

// Reviewer definitions
const reviewerDefs = [
  { name: 'Technical Reviewer', prompt: 'prd-council/core/technical-reviewer.md', skills: ['council/technical-review.md'] },
  { name: 'Security Reviewer', prompt: 'prd-council/core/security-reviewer.md', skills: ['council/security-review.md'] },
  { name: 'Executive Reviewer', prompt: 'prd-council/core/executive-reviewer.md', skills: ['council/business-alignment.md'] },
  { name: 'User Advocate', prompt: 'prd-council/core/user-advocate.md', skills: ['council/ux-review.md'] }
];

// Load prompts and skills for each reviewer
const reviewers = reviewerDefs.map((r, i) => {
  const promptPath = `${d.promptsDir}/${r.prompt}`;
  const prompt = fs.readFileSync(promptPath, 'utf8');

  const skillsContent = r.skills.map(s => {
    const skillPath = `${d.skillsDir}/${s}`;
    return fs.readFileSync(skillPath, 'utf8');
  }).join('\n\n---\n\n');

  return {
    index: i,
    name: r.name,
    prompt,
    skills: skillsContent
  };
});

// Return single item with reviewers array
return [{
  json: {
    ...d,
    reviewers
  }
}];

const d = $input.first().json;
const r = d.reviewers[0];
const sys = `${r.prompt}

# Skills

${r.skills}`;
const usr = `You are reviewing this PRD:

${d.prd}

Provide your review per the system prompt format.`;
return [{ json: { ...d, idx: 0, sys, usr } }];

const httpResp = $input.first().json;
const buildData = $('Code - Build R1 Request').first().json;

return [{ json: { ...buildData, r1: httpResp.response, r1name: 'Technical Reviewer' } }];

const d = $('Code - Save R1').first().json;
const r = d.reviewers[1];
const sys = `${r.prompt}

# Skills

${r.skills}`;
const usr = `You are reviewing this PRD:

${d.prd}

Provide your review per the system prompt format.`;
return [{ json: { ...d, sys, usr } }];

const httpResp = $input.first().json;
const buildData = $('Code - Build R2 Request').first().json;

return [{ json: { ...buildData, r2: httpResp.response, r2name: 'Security Reviewer' } }];

const d = $('Code - Save R2').first().json;
const r = d.reviewers[2];
const sys = `${r.prompt}

# Skills

${r.skills}`;
const usr = `You are reviewing this PRD:

${d.prd}

Provide your review per the system prompt format.`;
return [{ json: { ...d, sys, usr } }];

const httpResp = $input.first().json;
const buildData = $('Code - Build R3 Request').first().json;

return [{ json: { ...buildData, r3: httpResp.response, r3name: 'Executive Reviewer' } }];

const d = $('Code - Save R3').first().json;
const r = d.reviewers[3];
const sys = `${r.prompt}

# Skills

${r.skills}`;
const usr = `You are reviewing this PRD:

${d.prd}

Provide your review per the system prompt format.`;
return [{ json: { ...d, sys, usr } }];

const httpResp = $input.first().json;
const buildData = $('Code - Build R4 Request').first().json;

return [{ json: { ...buildData, r4: httpResp.response, r4name: 'User Advocate' } }];

const d = $('Code - Save R4').first().json;

// Note: In production, prompt/skill files would be read separately
// For MVP, using inline placeholders
const chairPromptPlaceholder = `You are the Council Chair. Synthesize all reviewer feedback into a unified assessment.

OUTPUT FORMAT:
## Consensus Points
[List areas where reviewers agree]

## Conflicts
[List areas where reviewers disagree]

## Overall Verdict
[APPROVED / APPROVED WITH CONCERNS / REVISE AND RESUBMIT]

## Required Revisions
[Numbered list if verdict is not APPROVED]`;

const sys = chairPromptPlaceholder;
const allRev = `## Reviewer Outputs

### ${d.r1name}

${d.r1}

---

### ${d.r2name}

${d.r2}

---

### ${d.r3name}

${d.r3}

---

### ${d.r4name}

${d.r4}

---`;

const usr = `Synthesize these 4 reviews into a unified council assessment:\n\n${allRev}`;

return [{ json: { ...d, sys, usr } }];

const httpResp = $input.first().json;
const buildData = $('Code - Build Chair Request').first().json;

const chair = httpResp.response;
const vm = chair.match(/Overall Verdict:\s*(APPROVED|APPROVED WITH CONCERNS|REVISE AND RESUBMIT)/i);
const verdict = vm ? vm[1] : 'APPROVED WITH CONCERNS';
const reviewText = `---
phase: council-review
project: ${buildData.project}
review_number: ${buildData.reviewNum}
date: ${new Date().toISOString().split('T')[0]}
prd_version_reviewed: ${buildData.prdV}
reviewers:
  - technical-reviewer
  - security-reviewer
  - executive-reviewer
  - user-advocate
  - council-chair
overall_verdict: ${verdict}
status: PENDING
---

# Council Review — ${buildData.project}

## Reviewer Outputs

### Technical Reviewer

${buildData.r1}

---

### Security Reviewer

${buildData.r2}

---

### Executive Reviewer

${buildData.r3}

---

### User Advocate

${buildData.r4}

---

## Council Chair Synthesis

${chair}

---

## User Decisions

**Status**: PENDING

User review in progress.

---

## PRD Revision Log

**PRD version before council**: ${buildData.prdV}
**PRD version after revisions**: (pending)

### Changes Made

(pending)

---

## Re-Review Status

**Gate Decision**: (pending)
**Decision Date**: (pending)
**Rationale**: (pending)
`;
return [{ json: { ...buildData, reviewText, verdict, response: chair } }];

const d = $input.first().json;
const councilText = $input.first().json.councilFileContent || '';
const decision = d.decision;
if (!decision) throw new Error('decision required (ACCEPTED or REJECTED)');

const revisions = d.revisions.trim();
const prdMatch = councilText.match(/prd_version_reviewed:\s*(v\d+)/);
const oldVer = prdMatch ? prdMatch[1] : 'v1';
const newVerNum = parseInt(oldVer.substring(1)) + 1;
const newVer = `v${newVerNum}`;

// Update council handoff with decision
const today = new Date().toISOString().split('T')[0];
const decisionBlock = `\n\n---\n## User Decision (${today})\n\n**Status**: ${decision}\n${revisions ? `\n**Revisions to Apply**:\n${revisions}\n` : ''}\n---\n`;
const updatedCouncil = councilText + decisionBlock;

return [{
  json: {
    ...d,
    decision,
    oldPrdVersion: oldVer,
    newPrdVersion: decision === 'ACCEPTED' ? newVer : oldVer,
    councilHandoffContent: updatedCouncil,
    message: `Decision recorded: ${decision}${decision === 'ACCEPTED' ? ` (PRD ${oldVer} → ${newVer})` : ''}`
  }
}];

const d = $input.first().json;
const councilText = $input.first().json.councilFileContent || '';
const gate = d.gateDecision;
if (!gate) throw new Error('gate_decision required (PROCEED or RECONVENE)');

const today = new Date().toISOString().split('T')[0];
const rationale = gate === 'PROCEED' ?
  'User approved proceeding to next phase.' :
  'User requested council reconvene for re-review.';

const gateBlock = `\n\n---\n## Re-Review Gate (${today})\n\n**Gate Decision**: ${gate}\n**Rationale**: ${rationale}\n---\n`;
const updatedCouncil = councilText + gateBlock;

const nextReviewFile = gate === 'RECONVENE' ?
  `${d.wp}/handoffs/004-council-review-r${d.reviewNum + 1}.md` :
  '';

return [{
  json: {
    ...d,
    gateDecision: gate,
    councilHandoffContent: updatedCouncil,
    nextReviewFile,
    message: `Gate decision: ${gate}${gate === 'RECONVENE' ? ` (next: r${d.reviewNum + 1})` : ''}`
  }
}];

const fs = require('fs');
const d = $input.first().json;
let councilFileContent;
try {
  councilFileContent = fs.readFileSync(d.councilHandoff, 'utf8');
} catch(e) {
  throw new Error(`Council review not found at ${d.councilHandoff}.`);
}
return [{ json: { ...d, councilFileContent } }];

const fs = require('fs');
const d = $input.first().json;
let councilFileContent;
try {
  councilFileContent = fs.readFileSync(d.councilHandoff, 'utf8');
} catch(e) {
  throw new Error(`Council review not found at ${d.councilHandoff}.`);
}
return [{ json: { ...d, councilFileContent } }];

const d = $input.first().json;
const decision = d.decision;
const revisions = (d.revisions || '').trim();

return [{
  json: {
    ...d,
    shouldRevise: decision === 'ACCEPTED' && revisions.length > 0
  }
}];

const fs = require('fs');
const d = $input.first().json;
let prd;
try {
  prd = fs.readFileSync(d.prdHandoff, 'utf8');
} catch(e) {
  throw new Error(`PRD not found at ${d.prdHandoff}.`);
}
return [{ json: { ...d, prd } }];

const d = $input.first().json;
const item = $input.first().json;
const currentPRD = item.prd || '';

// Extract version from PRD frontmatter
const versionMatch = currentPRD.match(/version:\s*(v\d+)/);
const currentVersion = versionMatch ? versionMatch[1] : 'v1';
const newVersionNum = parseInt(currentVersion.substring(1)) + 1;
const newVersion = `v${newVersionNum}`;

return [{
  json: {
    ...d,
    currentPRD,
    currentVersion,
    newVersion
  }
}];

const d = $input.first().json;

// Build PRD Writer prompt for revisions
const systemPrompt = `You are the PRD Writer. Apply the following council recommendations to the PRD below.

COUNCIL RECOMMENDATIONS TO APPLY:
${d.revisions}

CURRENT PRD (${d.currentVersion}):
${d.currentPRD}

INSTRUCTIONS:
- Apply ONLY the specific recommendations listed above
- Maintain all existing sections and structure
- Update the version in frontmatter to ${d.newVersion}
- Preserve all other content unchanged
- Output the complete updated PRD

OUTPUT: Complete revised PRD with version ${d.newVersion}`;

return [{
  json: {
    ...d,
    model: "qwen3.5:35b-a3b",
    prompt: systemPrompt,
    stream: False,
    temperature: 0.7,
    num_predict: 8000
  }
}];

const d = $input.first().json;
const resp = $input.first().json;
const revisedPRD = resp.response || '';

if (!revisedPRD || revisedPRD.length < 100) {
  throw new Error('PRD revision failed - empty or too short response');
}

const version = d.newVersion;  // newVersion passed through data flow

return [{
  json: {
    ...d,
    revisedPRD,
    newPrdVersion: version,
    prdFileName: `prd-${d.project}-${version}.md`
  }
}];

const fs = require('fs');
const d = $input.first().json;

// Create directory if needed
fs.mkdirSync(`/home/node/workspace/${d.project}/tasks`, { recursive: true });

// Write revised PRD
const prdPath = `/home/node/workspace/${d.project}/tasks/${d.prdFileName}`;
fs.writeFileSync(prdPath, d.revisedPRD, 'utf8');

return [{
  json: {
    ...d,
    prd_path: prdPath
  }
}];

const fs = require('fs');
const d = $input.first().json;

// Create directory if needed
fs.mkdirSync(`/home/node/workspace/${d.project}/handoffs`, { recursive: true });

// Update handoff file with revised PRD
fs.writeFileSync(d.prdHandoff, d.revisedPRD, 'utf8');

return [{ json: d }];

const d = $input.first().json;
const gate = d.gateDecision;

return [{
  json: {
    ...d,
    shouldReconvene: gate === 'RECONVENE'
  }
}];

const assembleData = $input.first().json;

// Prepare file write
const handoffPath = `/home/node/workspace/${assembleData.project}/handoffs/004-council-review.md`;

return [{
  json: assembleData,
  binary: {
    data: {
      data: assembleData.review_text,
      mimeType: 'text/markdown',
      fileName: handoffPath
    }
  }
}];
